	 ('ve_gully','form_feature','tab_data','district_id','lyt_data_3',NULL,'integer','combo','District:','District_id - identifier of the neighborhood with which the element is linked. To choose from those available in the drop-down (it is filtered according to the selected municipality)',NULL,false,false,true,false,NULL,'SELECT a.district_id AS id, a.name AS idval FROM ext_district a JOIN ext_municipality m USING (muni_id) WHERE district_id IS NOT NULL ',NULL,true,'muni_id',' AND m.muni_id',NULL,'{"setMultiline":false}',NULL,NULL,true,86),
