	 ('ve_gully_vgully','form_feature','tab_data','gullycat_id','lyt_top_1',2,'string','typeahead','Gullycat id:','Gullycat_id',NULL,true,false,true,false,NULL,'SELECT id, id AS idval FROM cat_gully WHERE id IS NOT NULL AND active IS TRUE ',NULL,NULL,'gully_type',' AND cat_gully.gully_type IS NULL OR cat_gully.gully_type',NULL,'{"setMultiline": false, "labelPosition": "top", "valueRelation": {"layer": "cat_grate", "activated": true, "keyColumn": "id", "nullValue": false, "valueColumn": "id", "filterExpression": null}}',NULL,NULL,false,2),
	 ('ve_gully_vgully','form_feature','tab_data','epa_type','lyt_top_1',3,'string','combo','Epa type:','Epa_type - Type of node to use for the hydraulic model. It is not necessary to enter it, it is automatic depending on the node type.',NULL,false,false,true,true,NULL,'SELECT id, id as idval FROM sys_feature_epa_type WHERE active IS TRUE AND feature_type = ''GULLY''',true,false,NULL,NULL,NULL,'{"setMultiline": false, "labelPosition": "top"}',NULL,NULL,false,3),
